Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    private static HttpClient CreateClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new MockHandler(handler));
    }

    // Happy path
    [TestMethod]
    public async Task FetchAsync_ReturnsContent()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // Cancellation: pass an already-cancelled token
    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        using var client = CreateClient((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage());
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Timeout: cancel after a short delay
    [TestMethod]
    public async Task FetchAsync_ThrowsOnTimeout()
    {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        using var client = CreateClient(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct); // simulates slow server
            return new HttpResponseMessage();
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Non-success status code
    [TestMethod]
    public async Task FetchAsync_ThrowsOnErrorStatus()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Minimal mock handler
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _func;
        public MockHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> func) => _func = func;
        protected override Task<HttpResponseMessage> SendAsync(HttpRequestMessage request, CancellationToken ct) => _func(request, ct);
    }
}
```

**Key patterns:**

| Scenario | Technique |
|---|---|
| **Cancellation** | Create a pre-cancelled `CancellationTokenSource` and pass its token |
| **Timeout** | Use `new CancellationTokenSource(TimeSpan)` to auto-cancel after a delay |
| **Mock HTTP** | Subclass `HttpMessageHandler` — avoids needing Moq or external libs |
| **Async tests** | Return `async Task` (not `void`); MSTest awaits them natively |

The `MockHandler` approach is preferred over mocking `HttpClient` directly because `HttpClient.GetAsync` isn't virtual — you must intercept at the `HttpMessageHandler.SendAsync` level.
